    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Pure and applied mathematics including statistics and analysis." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Literature, writing, and language studies." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events, civilizations, and cultural developments." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Title = "Introduction to Programming", CourseCode = "CS 101", Description = "Fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT and has published extensively on programming pedagogy.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Title = "Data Structures and Algorithms", CourseCode = "CS 201", Description = "In-depth study of data structures (lists, trees, graphs, hash tables) and algorithm design techniques. Includes complexity analysis and problem-solving strategies.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. James Rivera", InstructorBio = "Dr. Rivera specializes in algorithm optimization and competitive programming. He previously worked at Google Research and has coached multiple ICPC finalist teams.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Title = "Database Systems", CourseCode = "CS 340", Description = "Relational database design, SQL, normalization, transaction processing, and an introduction to NoSQL systems.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez spent a decade in industry building large-scale data platforms before transitioning to academia. Her research focuses on distributed databases.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Title = "Calculus I", CourseCode = "MATH 151", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Alan Whitfield", InstructorBio = "Dr. Whitfield is an award-winning educator with over 20 years of teaching experience. He is known for making advanced mathematics accessible to all students.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Title = "Linear Algebra", CourseCode = "MATH 220", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to computer graphics and machine learning.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma's research bridges pure mathematics and data science. She has developed open-source tools for computational linear algebra used by thousands worldwide.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Title = "Classical Mechanics", CourseCode = "PHYS 201", Description = "Newtonian mechanics, conservation laws, oscillations, and rotational dynamics. Lab component included.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Thu Lab 2:00–4:50 PM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an experimental physicist whose research involves precision measurements. He brings real-world lab experience into every lecture.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 7, Title = "Quantum Physics", CourseCode = "PHYS 330", Description = "Introduction to quantum mechanics: wave-particle duality, Schrödinger equation, atomic structure, and quantum entanglement.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. Elena Vasquez", InstructorBio = "Dr. Vasquez is a theoretical physicist with publications in Nature and Physical Review Letters. She specializes in quantum information theory.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 8, Title = "Creative Writing", CourseCode = "ENG 210", Description = "Workshop-based course in fiction and poetry writing. Students produce a portfolio of original works and participate in peer critique sessions.", Credits = 3, Schedule = "Wed 6:00–8:30 PM", InstructorName = "Prof. Michael Okafor", InstructorBio = "Prof. Okafor is a published novelist and poet whose works have been shortlisted for the Booker Prize. He brings a global literary perspective to the workshop.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 9, Title = "American Literature", CourseCode = "ENG 315", Description = "Survey of American literary movements from the colonial period to the present, including works by Hawthorne, Twain, Morrison, and contemporary authors.", Credits = 3, Schedule = "Tue/Thu 3:00–4:15 PM", InstructorName = "Dr. Angela Foster", InstructorBio = "Dr. Foster's scholarship focuses on African American literary traditions. She has authored three books and serves on the editorial board of American Literary History.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 10, Title = "World History: 1500 to Present", CourseCode = "HIST 102", Description = "Global history from the Age of Exploration through the modern era. Examines colonialism, revolutions, world wars, and globalization.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Thomas Nakamura", InstructorBio = "Dr. Nakamura is a global historian whose research on cross-cultural exchange has earned multiple fellowships. He has taught on four continents.", DepartmentId = 5, DepartmentName = "History", IsFeatured = true },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public void SubmitEnrollment(EnrollmentRequest request) => _enrollments.Add(request);
}

