@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<h1>Welcome to the University Course Catalog</h1>
<p class="lead">Browse our departments, explore courses, and submit your enrollment request.</p>

<h2 class="mt-4">Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.CourseCode</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@course.Credits credits &middot; @course.DepartmentName</p>
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-5">Departments</h2>
<div class="list-group">
    @foreach (var dept in departments)
    {
        <a href="departments/@dept.Id" class="list-group-item list-group-item-action">
            <strong>@dept.Code</strong> &mdash; @dept.Name
        </a>
    }
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@rendermode InteractiveServer

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-secondary w-100" @onclick="ClearFilters">Clear</button>
    </div>
</div>

@if (filteredCourses.Any())
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in filteredCourses)
            {
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}

@code {
    private string searchTerm = string.Empty;
    private int selectedDepartmentId;
    private List<Department> departments = new();
    private List<Course> filteredCourses = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        ApplyFilters();
    }

    private void ClearFilters()
    {
        searchTerm = string.Empty;
        selectedDepartmentId = 0;
        ApplyFilters();
    }

    protected override void OnParametersSet() => ApplyFilters();

    private void ApplyFilters()
    {
        filteredCourses = CatalogService.SearchCourses(
            string.IsNullOrWhiteSpace(searchTerm) ? null : searchTerm,
            selectedDepartmentId > 0 ? selectedDepartmentId : null);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course") - University Course Catalog</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">Course not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active">@course.CourseCode</li>
        </ol>
    </nav>

    <h1>@course.Title</h1>
    <span class="badge bg-secondary fs-6 mb-3">@course.CourseCode</span>

    <div class="row mt-3">
        <div class="col-md-8">
            <h3>Description</h3>
            <p>@course.Description</p>

            <h3 class="mt-4">Instructor</h3>
            <h5>@course.InstructorName</h5>
            <p>@course.InstructorBio</p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Details</h5>
                    <ul class="list-unstyled">
                        <li><strong>Credits:</strong> @course.Credits</li>
                        <li class="mt-2"><strong>Schedule:</strong> @course.Schedule</li>
                        <li class="mt-2"><strong>Department:</strong> <a href="departments/@course.DepartmentId">@course.DepartmentName</a></li>
                    </ul>
                    <a href="enroll" class="btn btn-success w-100 mt-3">Enroll in This Course</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    private Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

@page "/departments"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Departments - University Course Catalog</PageTitle>

<h1>Departments</h1>

<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-6 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@dept.Code</h6>
                    <p class="card-text">@dept.Description</p>
                    <a href="departments/@dept.Id" class="btn btn-outline-primary">View Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
    }
}

@page "/departments/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>@(department?.Name ?? "Department") - University Course Catalog</PageTitle>

@if (department is null)
{
    <div class="alert alert-warning">Department not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="departments">Departments</a></li>
            <li class="breadcrumb-item active">@department.Name</li>
        </ol>
    </nav>

    <h1>@department.Name (@department.Code)</h1>
    <p class="lead">@department.Description</p>

    <h2 class="mt-4">Courses</h2>

    @if (courses.Any())
    {
        <div class="list-group">
            @foreach (var course in courses)
            {
                <a href="courses/@course.Id" class="list-group-item list-group-item-action">
                    <div class="d-flex w-100 justify-content-between">
                        <h5 class="mb-1">@course.CourseCode - @course.Title</h5>
                        <small>@course.Credits credits</small>
                    </div>
                    <p class="mb-1">@course.Schedule</p>
                    <small class="text-muted">Instructor: @course.InstructorName</small>
                </a>
            }
        </div>
    }
    else
    {
        <p>No courses available for this department.</p>
    }
}

@code {
    [Parameter] public int Id { get; set; }
    private Department? department;
    private List<Course> courses = new();

    protected override void OnInitialized()
    {
        department = CatalogService.GetDepartment(Id);
        if (department is not null)
            courses = CatalogService.GetCoursesByDepartment(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Enrollment Request - University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to submit your enrollment request.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@model.StudentName</strong>. Your enrollment request for
            <strong>@courses.FirstOrDefault(c => c.Id == model.CourseId)?.Title</strong> has been received.</p>
        <a href="enroll" class="btn btn-outline-success">Submit Another Request</a>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <InputText id="studentName" class="form-control" @bind-Value="model.StudentName" />
            <ValidationMessage For="() => model.StudentName" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" class="form-control" @bind-Value="model.StudentId" />
            <ValidationMessage For="() => model.StudentId" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" class="form-select" @bind-Value="model.CourseId">
                <option value="0">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.CourseCode - @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.CourseId" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </EditForm>
}

@code {
