@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@rendermode InteractiveServer

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-secondary w-100" @onclick="ClearFilters">Clear</button>
    </div>
</div>

@if (filteredCourses.Any())
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in filteredCourses)
            {
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}

@code {
    private string searchTerm = string.Empty;
    private int selectedDepartmentId;
    private List<Department> departments = new();
    private List<Course> filteredCourses = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        ApplyFilters();
    }

    private void ClearFilters()
    {
        searchTerm = string.Empty;
        selectedDepartmentId = 0;
        ApplyFilters();
    }

    protected override void OnParametersSet() => ApplyFilters();

    private void ApplyFilters()
    {
        filteredCourses = CatalogService.SearchCourses(
            string.IsNullOrWhiteSpace(searchTerm) ? null : searchTerm,
            selectedDepartmentId > 0 ? selectedDepartmentId : null);
    }
}

